export function buildAssetTree(assets: AssetSummary[]): AssetTreeNode[] {
  const roots = new Map<string, MutableNode>();
  for (const asset of assets) {
    const rootKey = `ns::${asset.namespace}`;
    let node = roots.get(rootKey);
    if (!node) {
      node = {
