282	        fill={node.isCenter ? BRAND.selectedBg : redacted ? '#fafafa' : '#ffffff'}
283	        stroke={node.isCenter ? BRAND.primary : node.isMonitored ? '#91caff' : BRAND.border}
284	        strokeWidth={node.isCenter ? 2 : 1}
285	        strokeDasharray={redacted ? '4 3' : undefined}
286	      />
287	      <text
288	        x={10}
289	        y={21}
290	        fontSize={12}
291	        fontWeight={600}
292	        fill={redacted ? '#8c8c8c' : BRAND.ink}
293	        fontStyle={redacted ? 'italic' : undefined}
294	        style={{ pointerEvents: 'none' }}
295	      >
296	        {redacted ? '🔒 Restricted' : truncate(leafName(node.name ?? ''), 24)}
297	      </text>
298	      <text x={10} y={38} fontSize={10} fill="#8c8c8c" style={{ pointerEvents: 'none' }}>
299	        {/* The label, not the raw namespace: a node subtitle has ~28 characters, and
300	            an Iceberg namespace is a DSN — it truncated to `dev · postgresql+psy…`,
301	            which told the reader nothing. The full namespace stays in the <title>
302	            tooltip above (#830). */}
303	        {redacted
304	          ? 'outside your access'
305	          : truncate(
306	              node.env
307	                ? `${node.env} · ${namespaceLabel(node.namespace ?? '')}`
308	                : namespaceLabel(node.namespace ?? ''),
309	              28,
310	            )}
311	      </text>
312	      {/* Monitored must not be colour-only (WCAG 1.4.1): a filled dot marks it, so
313	          the state survives a colour-blind viewer and a greyscale print. */}
314	      {!node.isCenter && node.isMonitored && (
315	        <circle cx={NODE_W - 12} cy={12} r={3.5} fill={BRAND.primary} />
316	      )}
317	    </g>
318	  );
319	}
320	
321	/** The last dotted/slashed segment — the table/file, not the whole path. The full
322	 *  identity stays in the node's <title> tooltip. Reuses the one segmentation rule
323	 *  (`assetTree.nameSegments`, #802) so the two views can't drift. */
324	function leafName(name: string): string {
325	  return nameSegments(name).at(-1) ?? name;
326	}
327	
328	function truncate(text: string, max: number): string {
329	  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
330	}
