1	import { LockOutlined } from '@ant-design/icons';
2	import { Card, Empty, Flex, Tag, Typography } from 'antd';
3	
4	import type { LineageEdge, LineageNode } from '../../api/assets';
5	import { nameSegments } from './assetTree';
6	
7	/**
8	 * Column-level lineage for the asset under view (#901) — the direct edges that carry
9	 * a column-grain refinement, as `upstream column → downstream column` mappings.
10	 *
11	 * Redaction contract (the #845 one-rule, applied SERVER-side): an edge whose far
12	 * endpoint is outside the viewer's grants arrives with `columns: null` and only
13	 * `column_count` — rendered here as a locked box ("N column links · restricted
14	 * asset"), because a hidden asset's column names are schema disclosure. The panel
15	 * must never render that as "no column lineage": something maps, in N links —
16	 * the viewer just may not see what.
17	 *
18	 * Edges with neither field are table-grain only and are omitted; if no direct edge
19	 * carries the grain, the panel says so rather than rendering an empty card.
20	 */
21	export function ColumnLineagePanel({
22	  centerId,
23	  centerName,
24	  nodes,
25	  edges,
26	}: {
27	  centerId: string;
28	  centerName: string;
29	  nodes: LineageNode[];
30	  edges: LineageEdge[];
31	}) {
32	  const byId = new Map(nodes.map((n) => [n.id, n]));
33	  const label = (id: string): string => {
34	    if (id === centerId) return tableName(centerName);
35	    const node = byId.get(id);
36	    if (!node || !node.name) return 'Restricted asset';
37	    return tableName(node.name);
38	  };
39	  const direct = edges.filter(
40	    (e) =>
41	      (e.source === centerId || e.target === centerId) &&
42	      (e.columns != null || e.column_count != null),
43	  );
44	  return (
45	    <Card size="small" title="Column lineage">
46	      {direct.length === 0 ? (
47	        <Empty
48	          image={Empty.PRESENTED_IMAGE_SIMPLE}
49	          description="No column-level lineage recorded on this asset's direct edges"
50	        />
51	      ) : (
52	        <Flex vertical gap={12}>
53	          {direct.map((edge) => {
54	            const key = `${edge.source}->${edge.target}`;
55	            const redacted = edge.columns == null;
56	            return (
57	              <div key={key} data-testid={redacted ? 'column-edge-redacted' : 'column-edge'}>
58	                <Typography.Text strong>
59	                  {label(edge.source)} → {label(edge.target)}
60	                </Typography.Text>{' '}
61	                <Tag>{edge.column_count ?? edge.columns?.length ?? 0} column links</Tag>
62	                {redacted ? (
63	                  // The server withheld the pairs (far endpoint outside the viewer's
64	                  // grants) — an honest locked box, never an empty list.
65	                  <Typography.Paragraph type="secondary" style={{ marginBottom: 0 }}>
66	                    <LockOutlined /> Column mappings are hidden — they involve an asset you don't
67	                    have access to.
68	                  </Typography.Paragraph>
69	                ) : (
70	                  <Flex vertical gap={2} style={{ marginTop: 4 }}>
71	                    {(edge.columns ?? []).map(([up, down]) => (
72	                      <Typography.Text key={`${up}->${down}`} code>
73	                        {up} → {down}
74	                      </Typography.Text>
75	                    ))}
76	                  </Flex>
77	                )}
78	              </div>
79	            );
80	          })}
81	        </Flex>
82	      )}
83	    </Card>
84	  );
85	}
86	
87	/** The table's own segment of a dotted identity — the panel's rows are about
88	 *  columns, so the full `db.schema.table` label would drown them. */
89	function tableName(name: string): string {
90	  const segments = nameSegments(name);
91	  return segments[segments.length - 1] ?? name;
92	}
