38	/**
39	 * Asset detail (`/assets/:assetId`, #760) — identity header, health across the
40	 * composing suites (the acceptance criterion: renders ≥2 suites on a shared
41	 * asset), and upstream/downstream lineage lists. Links out to each suite and its
42	 * latest run. Read-only apart from the workspace-Admin-only description edit
43	 * (ADR 0034 §4); no navigation inversion (phase 4).
44	 */
45	export function AssetDetail() {
46	  const { assetId } = useParams<{ assetId: string }>();
47	  // Remount on id change. `useAsyncData` fetches on mount (and on reload) only, so
48	  // an asset→asset navigation — which the lineage graph's clickable nodes made
49	  // possible for the first time (#805) — would otherwise re-render this same
50	  // instance with a new URL but the PREVIOUS asset's data still on screen. Keying
51	  // the page on the id makes the route param the identity of the mount.
52	  return <AssetDetailPage key={assetId} assetId={assetId} />;
53	}
54	
55	function AssetDetailPage({ assetId }: { assetId: string | undefined }) {
56	  const navigate = useNavigate();
57	  const { state, reload } = useAsyncData(() => {
58	    if (!assetId) throw new Error('no asset');
59	    return getAsset(assetId);
60	  });
61	
62	  return (
63	    <Page gap={16}>
64	      <div>
65	        <Button
66	          type="text"
67	          icon={<ArrowLeftOutlined />}
68	          onClick={() => navigate('/assets')}
69	          style={{ paddingLeft: 0 }}
70	        >
71	          Assets
72	        </Button>
73	      </div>
74	      <AsyncBody state={state} loadingText="Loading asset…" errorTitle="Failed to load asset">
75	        {(asset) => (
76	          <AssetDetailBody
77	            asset={asset}
78	            onOpenRun={(id) => navigate(`/results/${id}`)}
79	            onChanged={reload}
80	          />
81	        )}
82	      </AsyncBody>
83	    </Page>
84	  );
85	}
86	
87	function AssetDetailBody({
88	  asset,
89	  onOpenRun,
90	  onChanged,
91	}: {
92	  asset: AssetDetailData;
93	  onOpenRun: (runId: string) => void;
94	  onChanged: () => void;
95	}) {
96	  const { summary } = asset;
97	  const navigate = useNavigate();
98	  // Asset-metadata mutation is workspace-Admin-only (ADR 0034 §4; backend 403s
99	  // everyone else) — the edit affordance renders only for admins. This gate is
100	  // nav convenience, not the security boundary (that's the PATCH's 403).
101	  const isAdmin = useIsWorkspaceAdmin();
102	  return (
103	    <Flex vertical gap={20}>
104	      <Flex justify="space-between" align="flex-start" gap={12} wrap>
105	        <Flex vertical gap={4} style={{ minWidth: 0 }}>
106	          <Typography.Title level={3} style={{ margin: 0 }}>
107	            {summary.name}
108	          </Typography.Title>
109	          {/* The human label reads; the raw OL namespace stays the identity, so it's
110	              what `copyable` copies and what the tooltip reveals (#830). */}
111	          <Tooltip title={summary.namespace}>
112	            <Typography.Text type="secondary" copyable={{ text: summary.namespace }}>
113	              {namespaceLabel(summary.namespace)}
114	            </Typography.Text>
115	          </Tooltip>
116	        </Flex>
117	        {/* Two health axes, deliberately separate (#803): "can we reach it?" vs
118	            "is the data good?". The old single badge conflated them, so a
119	            datasource DataQ couldn't even connect to read as a data failure. */}
120	        <Flex gap={16} align="center" wrap>
121	          {summary.env && <Tag>{summary.env}</Tag>}
122	          <HealthAxis
123	            label="Connection"
124	            health={connectionHealth(summary)}
125	            hint="Whether DataQ could reach and execute against the datasource behind this asset."
126	          />
127	          <HealthAxis
128	            label="Data quality"
129	            health={suiteHealth(summary)}
130	            hint="The severity-weighted verdict of the suites on this asset. Operational errors are excluded."
131	          />
132	        </Flex>
133	      </Flex>
134	
135	      <DescriptionBlock
136	        assetId={summary.id}
137	        description={summary.description}
138	        canEdit={isAdmin}
139	        onChanged={onChanged}
140	      />
141	
142	      {/* Mount-gated (not closure-gated) on adminness: useAsyncData only re-runs
143	          its fetcher on [nonce], so a fetcher that closed over a still-false
144	          `isAdmin` would never re-fire once /me resolves (admin deep-link/refresh
145	          race). Mounting the block only when adminness is KNOWN true means its
146	          on-mount fetch always runs with the right identity — and a non-admin
147	          structurally never hits the admin-only endpoint. */}
148	      {isAdmin && (
149	        <OwnerBlock
150	          assetId={summary.id}
151	          ownerUserId={summary.owner_user_id}
152	          onChanged={onChanged}
153	        />
154	      )}
155	
156	      <SuitesSection
157	        suites={asset.suites}
158	        onOpenSuite={(id) => navigate(`/suites/${id}`)}
159	        onOpenRun={onOpenRun}
160	      />
161	
162	      <IncidentsPanel
163	        assetId={summary.id}
164	        permissionBySuite={Object.fromEntries(
165	          asset.suites.map((s) => [s.suite_id, s.my_permission]),
166	        )}
167	      />
168	
169	      {/* One left-to-right graph (#805) — provenance → this asset → blast radius —
170	          replacing the two separate upstream/downstream list boxes. */}
171	      <LineageGraph
172	        center={{
173	          id: summary.id,
174	          // A detail summary is never redacted (the endpoint 404s those) — coerce for the shared type.
175	          name: summary.name ?? '',
176	          namespace: summary.namespace,
177	          env: summary.env,
178	        }}
179	        upstream={asset.upstream}
180	        downstream={asset.downstream}
181	        edges={asset.lineage_edges}
182	        failingSources={asset.failing_lineage_sources}
183	        warehouseStatus={asset.warehouse_lineage_status}
184	        onOpenAsset={(id) => navigate(`/assets/${id}`)}
185	      />
186	
187	      {/* Column-grain refinement of the direct edges (#901); redacted far-endpoints
188	          arrive count-only from the server and render as a locked box (#845). */}
189	      <ColumnLineagePanel
190	        centerId={summary.id}
191	        centerName={summary.name ?? ''}
192	        nodes={[...asset.upstream, ...asset.downstream]}
193	        edges={asset.lineage_edges}
194	      />
195	    </Flex>
196	  );
197	}
198	
199	/**
200	 * One labelled health axis (#803) — the label makes explicit *which* health this
201	 * is, so "Errors" on Connection can never be misread as a data failure (and vice
202	 * versa). The hint is a tooltip on the label, not a wall of text on the page.
203	 */
204	function HealthAxis({ label, health, hint }: { label: string; health: Health; hint: string }) {
205	  return (
206	    <Flex gap={6} align="center">
207	      <Tooltip title={hint}>
208	        <Typography.Text type="secondary" style={{ fontSize: 12, cursor: 'help' }}>
209	          {label}
210	        </Typography.Text>
211	      </Tooltip>
212	      <Tag color={health.color} style={{ marginInlineEnd: 0 }}>
213	        {health.label}
214	      </Tag>
215	    </Flex>
216	  );
217	}
