219	/**
220	 * The asset description + the workspace-Admin-only inline edit (#760). Owner
221	 * reassignment lives in its own `OwnerBlock` below (#773).
222	 */
223	function DescriptionBlock({
224	  assetId,
225	  description,
226	  canEdit,
227	  onChanged,
228	}: {
229	  assetId: string;
230	  description: string | null;
231	  canEdit: boolean;
232	  onChanged: () => void;
233	}) {
234	  const { message } = App.useApp();
235	  const [editing, setEditing] = useState(false);
236	  const [draft, setDraft] = useState('');
237	  const [saving, setSaving] = useState(false);
238	
239	  const openEditor = () => {
240	    setDraft(description ?? '');
241	    setEditing(true);
242	  };
243	
244	  const onSave = async () => {
245	    setSaving(true);
246	    try {
247	      // Empty draft clears the description (explicit null — the PATCH's
248	      // omitted-vs-null semantics make that an intentional unset).
249	      await updateAsset(assetId, { description: draft.trim() || null });
250	      message.success('Description updated');
251	      setEditing(false);
252	      onChanged();
253	    } catch (err) {
254	      message.error(`Update failed: ${errorMessage(err)}`);
255	    } finally {
256	      setSaving(false);
257	    }
258	  };
259	
260	  if (!description && !canEdit) return null;
261	  return (
262	    <>
263	      <Flex gap={8} align="baseline" wrap>
264	        {description ? (
265	          <Typography.Paragraph style={{ margin: 0 }}>{description}</Typography.Paragraph>
266	        ) : (
267	          <Typography.Text type="secondary">No description yet.</Typography.Text>
268	        )}
269	        {canEdit && (
270	          <Button type="link" size="small" icon={<EditOutlined />} onClick={openEditor}>
271	            Edit
272	          </Button>
273	        )}
274	      </Flex>
275	      <Modal
276	        title="Edit asset description"
277	        open={editing}
278	        onOk={() => void onSave()}
279	        okText="Save"
280	        confirmLoading={saving}
281	        onCancel={() => setEditing(false)}
282	        destroyOnHidden
283	      >
284	        <Input.TextArea
285	          rows={3}
286	          maxLength={1024}
287	          showCount
288	          value={draft}
289	          onChange={(e) => setDraft(e.target.value)}
290	          placeholder="What is this asset, and who should care when it breaks?"
291	        />
292	      </Modal>
293	    </>
294	  );
295	}
296	
297	/**
298	 * Asset owner + the workspace-Admin-only reassignment (#773). Asset owners feed
299	 * ADR 0034 §3 incident routing, so keeping them assignable matters. The picker is
300	 * sourced from `GET /admin/users` (itself admin-only — a clean fit, since the
301	 * whole control is admin-gated); the current owner renders as a display
302	 * name/email, never a bare UUID, once the user list resolves.
303	 *
304	 * **Mounted only for admins** (the parent gates on `isAdmin`) — so the on-mount
305	 * user-list fetch always runs with adminness known, and a non-admin structurally
306	 * never calls the admin-only endpoint. This gate is nav convenience — the PATCH's
307	 * `require_workspace_admin` 403 is the security boundary.
308	 */
309	function OwnerBlock({
310	  assetId,
311	  ownerUserId,
312	  onChanged,
313	}: {
314	  assetId: string;
315	  ownerUserId: string | null;
316	  onChanged: () => void;
317	}) {
318	  const { message } = App.useApp();
319	  // Fetches on mount — safe because this component only mounts for admins.
320	  const { state } = useAsyncData(listAdminUsers);
321	  const [editing, setEditing] = useState(false);
322	  // Controlled select value: `undefined` = unassigned (renders the placeholder).
323	  const [draft, setDraft] = useState<string | undefined>(undefined);
324	  const [saving, setSaving] = useState(false);
325	
326	  const loadFailed = state.status === 'error';
327	  const users: AdminUser[] = state.status === 'ok' ? state.data : [];
328	  const label = (u: AdminUser) => u.display_name || u.email;
329	  const owner = users.find((u) => u.id === ownerUserId);
330	  // Prefer the resolved name/email; fall back to the raw id only if the list
331	  // hasn't loaded or the owner is somehow not in it (never leave a blank).
332	  const ownerText = ownerUserId === null ? 'Unassigned' : owner ? label(owner) : ownerUserId;
333	
334	  const openEditor = () => {
335	    setDraft(ownerUserId ?? undefined);
336	    setEditing(true);
337	  };
338	
339	  const onSave = async () => {
340	    setSaving(true);
341	    try {
342	      // `undefined` draft → explicit null (unassign); otherwise the chosen id.
343	      await updateAsset(assetId, { owner_user_id: draft ?? null });
344	      message.success('Owner updated');
345	      setEditing(false);
346	      onChanged();
347	    } catch (err) {
348	      message.error(`Update failed: ${errorMessage(err)}`);
349	    } finally {
350	      setSaving(false);
351	    }
352	  };
353	
354	  return (
355	    <>
356	      <Flex gap={8} align="center" wrap>
357	        <UserOutlined style={{ color: '#8c8c8c' }} />
358	        <Typography.Text type="secondary">Owner:</Typography.Text>
359	        {ownerUserId === null ? (
360	          <Typography.Text type="secondary">{ownerText}</Typography.Text>
361	        ) : (
362	          <Typography.Text>{ownerText}</Typography.Text>
363	        )}
364	        <Button
365	          type="link"
366	          size="small"
367	          icon={<EditOutlined />}
368	          onClick={openEditor}
369	          disabled={loadFailed}
370	        >
371	          Reassign owner
372	        </Button>
373	        {/* A failed /admin/users read must not degrade to a silently-empty
374	            picker — say so (mirrors the AssetHealthLead unavailable state). */}
375	        {loadFailed && (
376	          <Typography.Text type="secondary">
377	            The user list is unavailable right now.
378	          </Typography.Text>
379	        )}
380	      </Flex>
381	      <Modal
382	        title="Reassign asset owner"
383	        open={editing}
384	        onOk={() => void onSave()}
385	        okText="Save"
386	        confirmLoading={saving}
387	        onCancel={() => setEditing(false)}
388	        destroyOnHidden
389	      >
390	        <Select<string>
391	          style={{ width: '100%' }}
392	          placeholder="Unassigned"
393	          allowClear
394	          showSearch
395	          loading={state.status === 'loading'}
396	          value={draft}
397	          onChange={(value) => setDraft(value)}
398	          optionFilterProp="label"
399	          options={users.map((u) => ({ value: u.id, label: label(u) }))}
400	        />
401	      </Modal>
402	    </>
403	  );
404	}
405	
406	function SuitesSection({
407	  suites,
408	  onOpenSuite,
409	  onOpenRun,
410	}: {
411	  suites: ComposingSuite[];
412	  onOpenSuite: (suiteId: string) => void;
413	  onOpenRun: (runId: string) => void;
414	}) {
415	  const columns: ColumnsType<ComposingSuite> = [
416	    {
417	      title: 'Suite',
418	      dataIndex: 'name',
419	      render: (name: string, suite) => (
420	        <Button type="link" style={{ padding: 0 }} onClick={() => onOpenSuite(suite.suite_id)}>
421	          {name}
422	        </Button>
423	      ),
424	    },
425	    {
426	      title: 'Access',
427	      dataIndex: 'my_permission',
428	      width: 100,
429	      render: (level: string) => <Tag>{level}</Tag>,
430	    },
431	    {
432	      title: 'Health',
433	      key: 'health',
434	      width: 120,
435	      render: (_: unknown, suite) => {
436	        const { label, color } = runHealth(suite.latest_run);
437	        return <Tag color={color}>{label}</Tag>;
438	      },
439	    },
440	    {
441	      title: 'Checks',
442	      key: 'checks',
443	      width: 90,
444	      align: 'center',
445	      render: (_: unknown, suite) => {
446	        const r = suite.latest_run;
447	        return r.checks_total === 0 ? '—' : `${r.checks_passed} / ${r.checks_total}`;
448	      },
449	    },
450	    {
451	      title: 'Last run',
452	      key: 'last_run',
453	      width: 200,
454	      render: (_: unknown, suite) => {
455	        const r = suite.latest_run;
456	        const ts = formatTimestamp(r.finished_at ?? r.created_at);
457	        if (r.run_id) {
458	          return (
459	            <Button
460	              type="link"
461	              style={{ padding: 0 }}
462	              onClick={() => onOpenRun(r.run_id as string)}
463	            >
464	              {ts}
465	            </Button>
466	          );
467	        }
468	        return <Typography.Text type="secondary">—</Typography.Text>;
469	      },
470	    },
471	  ];
472	  return (
473	    <Card
474	      size="small"
475	      title={`Monitored by ${suites.length} suite${suites.length === 1 ? '' : 's'}`}
476	    >
477	      <Table<ComposingSuite>
478	        scroll={{ x: 'max-content' }}
479	        rowKey="suite_id"
480	        size="small"
481	        columns={columns}
482	        dataSource={suites}
483	        pagination={false}
484	      />
485	    </Card>
486	  );
487	}
