3	/**
4	 * Lineage graph layout (#805) — pure, so the geometry is unit-testable without
5	 * rendering anything (kept out of the `.tsx`).
6	 *
7	 * The asset under view sits in the middle; its **upstream** provenance fans out to
8	 * the left and its **downstream** blast radius to the right, one column per hop.
9	 * The backend gives us each neighbour's hop `depth` and the *real* edges between
10	 * them (`lineage_edges`), so a depth-2 node is drawn hanging off the depth-1 node
11	 * it actually descends from — never off the centre it has no edge to.
12	 *
13	 * Signed-depth columns: upstream depth `d` → column `-d`, the centre → `0`,
14	 * downstream depth `d` → column `+d`. Sorting the distinct columns left-to-right
15	 * therefore lays provenance → asset → consumers out in reading order.
16	 *
17	 * No graph library: the layout is a layered DAG we can place ourselves, and an
18	 * inline SVG scrolls horizontally inside its card on a phone far more simply than
19	 * a pan/zoom canvas would (and adds no dependency to license-check).
20	 */
21	
22	export const NODE_W = 190;
23	export const NODE_H = 52;
24	const COL_GAP = 72;
25	const ROW_GAP = 14;
26	const PAD = 12;
27	
28	export interface LaidOutNode {
29	  id: string;
30	  /** Null for a redacted neighbour (#845) — the renderer shows a locked placeholder. */
31	  name: string | null;
32	  namespace: string | null;
33	  env: string | null;
34	  isMonitored: boolean;
35	  /** False → outside the viewer's grants: redacted, and never clickable. */
36	  isAccessible: boolean;
37	  /** The asset under view — rendered as the anchor and not clickable. */
38	  isCenter: boolean;
39	  x: number;
40	  y: number;
41	}
42	
43	export interface LaidOutEdge {
44	  id: string;
45	  /** SVG cubic-bezier `d`, left edge of the source to right edge of the target. */
46	  path: string;
47	}
48	
49	export interface LineageLayout {
50	  nodes: LaidOutNode[];
51	  edges: LaidOutEdge[];
52	  width: number;
53	  height: number;
54	}
55	
56	/** The asset under view, as the graph's centre node. */
57	export interface CenterAsset {
58	  id: string;
59	  name: string;
60	  namespace: string;
61	  env: string | null;
62	}
63	
64	/**
65	 * Lay the neighbourhood out into hop columns and bezier edges.
66	 *
67	 * Edges whose endpoints aren't both in the neighbourhood are dropped rather than
68	 * drawn to nowhere (defensive: the backend only returns edges it traversed, but a
69	 * dangling edge must never throw or render a line into empty space).
70	 */
71	export function buildLineageLayout(
72	  center: CenterAsset,
73	  upstream: LineageNode[],
74	  downstream: LineageNode[],
75	  edges: LineageEdge[],
76	): LineageLayout {
77	  // Signed-depth column per node: upstream left (negative), downstream right.
78	  const placed: { node: LaidOutNode; col: number }[] = [
79	    {
80	      node: { ...center, isMonitored: true, isAccessible: true, isCenter: true, x: 0, y: 0 },
81	      col: 0,
82	    },
83	  ];
84	  // Nothing enforces an acyclic lineage graph (the per-direction BFS is cycle-safe
85	  // via its own visited set, but the up-walk and down-walk are independent, and a
86	  // catalog can emit a cycle). With A→B and B→A, B comes back as BOTH upstream and
87	  // downstream — so place each asset once, first occurrence winning, or we'd emit
88	  // two nodes sharing an id: duplicate React keys, and edges anchored to whichever
89	  // copy `byId` happened to keep.
90	  const seen = new Set<string>([center.id]);
91	  const place = (n: LineageNode, col: number) => {
92	    if (seen.has(n.id)) return;
93	    seen.add(n.id);
94	    placed.push({
95	      node: {
96	        id: n.id,
97	        name: n.name,
98	        namespace: n.namespace,
99	        env: n.env,
100	        isMonitored: n.is_monitored,
101	        isAccessible: n.is_accessible,
102	        isCenter: false,
103	        x: 0,
104	        y: 0,
105	      },
106	      col,
107	    });
108	  };
109	  for (const n of upstream) place(n, -n.depth);
110	  for (const n of downstream) place(n, n.depth);
111	
112	  // Group by column, then order the columns left → right by signed depth.
113	  const byCol = new Map<number, LaidOutNode[]>();
114	  for (const { node, col } of placed) {
115	    const bucket = byCol.get(col);
116	    if (bucket) bucket.push(node);
117	    else byCol.set(col, [node]);
118	  }
119	  const cols = [...byCol.keys()].sort((a, b) => a - b);
120	
121	  const colHeight = (n: number) => n * NODE_H + Math.max(0, n - 1) * ROW_GAP;
122	  const tallest = Math.max(...cols.map((c) => colHeight(byCol.get(c)?.length ?? 0)));
123	
124	  cols.forEach((col, i) => {
125	    const nodes = byCol.get(col) ?? [];
126	    // Centre each column vertically against the tallest one, so the graph reads
127	    // as a spine rather than a ragged top-aligned stack.
128	    const top = PAD + (tallest - colHeight(nodes.length)) / 2;
129	    nodes.forEach((node, j) => {
130	      node.x = PAD + i * (NODE_W + COL_GAP);
131	      node.y = top + j * (NODE_H + ROW_GAP);
132	    });
133	  });
134	
135	  const nodes = placed.map((p) => p.node);
136	  const byId = new Map(nodes.map((n) => [n.id, n]));
137	
138	  const laidOutEdges: LaidOutEdge[] = [];
139	  for (const e of edges) {
140	    const from = byId.get(e.source);
141	    const to = byId.get(e.target);
142	    if (!from || !to) continue; // dangling — never draw a line into empty space
143	    laidOutEdges.push({ id: `${e.source}->${e.target}`, path: bezier(from, to) });
144	  }
145	
146	  return {
147	    nodes,
148	    edges: laidOutEdges,
149	    width: PAD * 2 + cols.length * NODE_W + Math.max(0, cols.length - 1) * COL_GAP,
150	    height: PAD * 2 + tallest,
151	  };
152	}
153	
154	/** A cubic bezier from the source node's right edge to the target's left edge. */
155	function bezier(from: LaidOutNode, to: LaidOutNode): string {
156	  const sx = from.x + NODE_W;
157	  const sy = from.y + NODE_H / 2;
158	  const tx = to.x;
159	  const ty = to.y + NODE_H / 2;
160	  // Clamped control offset: keeps the curve readable even for a same-column or
161	  // backwards edge, where (tx - sx) would otherwise be zero or negative.
162	  const dx = Math.max(24, (tx - sx) / 2);
163	  return `M ${sx} ${sy} C ${sx + dx} ${sy}, ${tx - dx} ${ty}, ${tx} ${ty}`;
164	}
165

