1	import { ArrowRightOutlined, DatabaseOutlined } from '@ant-design/icons';
2	import { Card, Empty, Flex, Grid, Spin, Tag, Tooltip, Typography } from 'antd';
3	import { useNavigate } from 'react-router-dom';
4	
5	import { type AssetSummary, listAssets } from '../../api/assets';
6	import { AssetHealthTag } from '../assets/AssetHealthTag';
7	import { namespaceLabel } from '../assets/namespaceLabel';
8	import { useAsyncData } from '../../hooks/useAsyncData';
9	import { BRAND } from '../../theme';
10	
11	/**
12	 * Asset-health lead (`/dashboard`, ADR 0034 navigation inversion, #773) — the
13	 * dashboard now *leads* with asset-level health: how many assets DataQ monitors,
14	 * how many need attention, how many have a run in flight. Everything is derived
15	 * from the existing `/assets` list read (no new endpoint) and filtered to the
16	 * caller's grants by the backend, so this leaks nothing.
17	 *
18	 * Click-through is preserved end to end: the tiles and "View all assets" go to
19	 * `/assets`; each attention row opens `/assets/:id` (→ its suites/runs).
20	 */
21	
22	/** An asset "needs attention" when a check tier is failing (bad data) or DataQ
23	 *  couldn't execute against the datasource at all (#803 connection axis — a failed
24	 *  run, or a check the datasource threw on). An active-but-unconcluded run is *in
25	 *  progress*, not failing. `has_operational_error` subsumes `has_failed_run`, and
26	 *  additionally catches a run that *succeeded* while its checks errored — which the
27	 *  old run-status-only rule silently let read as healthy. */
28	function needsAttention(a: AssetSummary): boolean {
29	  return a.worst_severity !== null || a.has_operational_error;
30	}
31	
32	/** Attention ordering: critical > fail > warn > operational run failure. The
33	 *  backend list arrives (namespace, name)-alphabetical, so without this a page
34	 *  of warns could hide a critical asset behind the "+N more" fold. */
35	const SEVERITY_RANK: Record<'warn' | 'fail' | 'critical', number> = {
36	  warn: 1,
37	  fail: 2,
38	  critical: 3,
39	};
40	function attentionRank(a: AssetSummary): number {
41	  return a.worst_severity ? SEVERITY_RANK[a.worst_severity] : 0;
42	}
43	
44	/** How many attention rows to surface inline before deferring to the full list. */
45	const ATTENTION_PREVIEW = 5;
46	
47	/** The backend caps `GET /assets` at 200 rows (its default == its max). A result
48	 *  exactly at the cap means the widget may be looking at a truncated slice — the
49	 *  counts must say so rather than silently undercount. */
50	const LIST_CAP = 200;
51	
52	export function AssetHealthLead() {
53	  const navigate = useNavigate();
54	  const { state } = useAsyncData(() => listAssets());
55	
56	  return (
57	    <Card
58	      size="small"
59	      styles={{ body: { paddingTop: 12 } }}
60	      title={
61	        <Flex align="center" gap={8}>
62	          <DatabaseOutlined style={{ color: BRAND.primary }} />
63	          <span>Asset health</span>
64	        </Flex>
65	      }
66	      extra={
67	        <Typography.Link onClick={() => navigate('/assets')}>
68	          View all assets <ArrowRightOutlined />
69	        </Typography.Link>
70	      }
71	    >
72	      {state.status === 'loading' && <Spin />}
73	      {state.status === 'error' && (
74	        <Typography.Text type="secondary">Asset health is unavailable right now.</Typography.Text>
75	      )}
76	      {state.status === 'ok' && (
77	        <AssetHealthBody
78	          assets={state.data}
79	          onOpenList={() => navigate('/assets')}
80	          onOpenAsset={(id) => navigate(`/assets/${id}`)}
81	        />
82	      )}
83	    </Card>
84	  );
85	}
86	
87	function AssetHealthBody({
88	  assets,
89	  onOpenList,
90	  onOpenAsset,
91	}: {
92	  assets: AssetSummary[];
93	  onOpenList: () => void;
94	  onOpenAsset: (id: string) => void;
95	}) {
96	  const screens = Grid.useBreakpoint();
97	  const stacked = screens.sm === false;
98	
99	  if (assets.length === 0) {
100	    return (
101	      <Empty
102	        image={Empty.PRESENTED_IMAGE_SIMPLE}
103	        description="No monitored assets yet — give a suite a run target and it will appear here."
104	      />
105	    );
106	  }
107	
108	  // Worst first (stable within a tier — Array.prototype.sort is stable), so a
109	  // critical asset can never hide behind five alphabetically-earlier warns.
110	  const attention = assets
111	    .filter(needsAttention)
112	    .sort((x, y) => attentionRank(y) - attentionRank(x));
113	  const active = assets.filter((a) => !needsAttention(a) && a.has_active_run);
114	  const truncated = assets.length >= LIST_CAP;
115	
116	  const tiles: { label: string; value: number; tone: string }[] = [
117	    // Redacted rows (#920) are present in browse but are not the viewer's
118	    // monitored assets — counting them would mislabel the stat.
119	    {
120	      label: 'Monitored',
121	      value: assets.filter((a) => a.is_accessible !== false).length,
122	      tone: BRAND.ink,
123	    },
124	    {
125	      label: 'Need attention',
126	      value: attention.length,
127	      tone: attention.length ? '#cf1322' : BRAND.ink,
128	    },
129	    { label: 'In progress', value: active.length, tone: BRAND.ink },
130	  ];
131	
132	  return (
133	    <Flex vertical gap={16}>
134	      {/* Summary strip — each tile is a click-through to the full assets list. */}
135	      <Flex gap={12} vertical={stacked}>
136	        {tiles.map((t) => (
137	          <Card
138	            key={t.label}
139	            size="small"
140	            className="dq-card--interactive"
141	            style={{ flex: 1, cursor: 'pointer' }}
142	            styles={{ body: { padding: '12px 16px' } }}
143	            onClick={onOpenList}
144	          >
145	            <Flex vertical gap={2}>
146	              <Typography.Text type="secondary" style={{ fontSize: 12 }}>
147	                {t.label}
148	              </Typography.Text>
149	              <Typography.Text strong style={{ fontSize: 22, color: t.tone }}>
150	                {t.value}
151	              </Typography.Text>
152	            </Flex>
153	          </Card>
154	        ))}
155	      </Flex>
156	
157	      {/* Honest truncation: at the cap we can't know how many assets exist
158	          beyond this slice, so the tiles above are a lower bound — say so
159	          explicitly instead of silently undercounting. */}
160	      {truncated && (
161	        <Typography.Text type="secondary" style={{ fontSize: 12 }}>
162	          Showing the first {LIST_CAP} assets — open Assets for the full list.
163	        </Typography.Text>
164	      )}
165	
166	      {/* Attention list: the assets a data owner should look at first. When all
167	          is well, say so rather than showing an empty box. */}
168	      {attention.length === 0 ? (
169	        <Typography.Text type="secondary">All monitored assets are healthy.</Typography.Text>
170	      ) : (
171	        <Flex vertical gap={8}>
172	          <Typography.Text strong style={{ fontSize: 13 }}>
173	            Needs attention
174	          </Typography.Text>
175	          {attention.slice(0, ATTENTION_PREVIEW).map((a) => (
176	            <Flex
177	              key={a.id}
178	              className="dq-suite-row"
179	              justify="space-between"
180	              align="center"
181	              gap={12}
182	              wrap
183	              onClick={() => onOpenAsset(a.id)}
184	              style={{ cursor: 'pointer', padding: '6px 8px', borderRadius: 6 }}
185	            >
186	              <Flex vertical gap={0} style={{ minWidth: 0 }}>
187	                <Typography.Text strong ellipsis style={{ maxWidth: 360 }}>
188	                  {a.name}
189	                </Typography.Text>
190	                <Tooltip title={a.namespace}>
191	                  <Typography.Text type="secondary" style={{ fontSize: 12 }} ellipsis>
192	                    {namespaceLabel(a.namespace)}
193	                  </Typography.Text>
194	                </Tooltip>
195	              </Flex>
196	              <Flex gap={8} align="center">
197	                {a.env && <Tag>{a.env}</Tag>}
198	                <AssetHealthTag summary={a} />
199	              </Flex>
200	            </Flex>
201	          ))}
202	          {attention.length > ATTENTION_PREVIEW && (
203	            <Typography.Link onClick={onOpenList}>
204	              +{attention.length - ATTENTION_PREVIEW} more
205	            </Typography.Link>
206	          )}
207	        </Flex>
208	      )}
209	    </Flex>
210	  );
211	}
